const readPdfFile = (file, cb, onErr) => {
  if (!file) return;
  if (file.type !== "application/pdf") return onErr("Please attach a PDF file.");
  if (file.size > 3.5 * 1024 * 1024) return onErr("PDF must be under 3.5 MB. Scan at a lower resolution if needed.");
  const reader = new FileReader();
  reader.onload = () => cb({ name: file.name, dataUrl: reader.result });
  reader.onerror = () => onErr("Couldn't read that file. Try again.");
  reader.readAsDataURL(file);
};
const openPdfDataUrl = (dataUrl) => {
  try {
    const b64 = dataUrl.split(",")[1];
    const bin = atob(b64);
    const bytes = new Uint8Array(bin.length);
    for (let i = 0; i < bin.length; i++) bytes[i] = bin.charCodeAt(i);
    const url = URL.createObjectURL(new Blob([bytes], { type: "application/pdf" }));
    window.open(url, "_blank");
  } catch (e) { alert("Couldn't open that PDF."); }
};

function isDirectVideoFile(url) {
  return /\.(mp4|webm|ogv|mov|m4v)(\?|#|$)/i.test(String(url || "").trim());
}

function VideoPlayer({ url, title }) {
  if (isDirectVideoFile(url)) {
    return (
      <video controls preload="metadata" playsInline title={title || "Guardian shield video"}
        style={{ width: "100%", height: "100%", display: "block", background: "#000" }}>
        <source src={String(url).trim()} />
        Your browser does not support video playback.
      </video>
    );
  }
  return (
    <iframe src={toEmbedUrl(url)} title={title || "Guardian shield video"}
      style={{ width: "100%", height: "100%", border: "none", display: "block" }}
      allow="accelerometer; autoplay; clipboard-write; encrypted-media; gyroscope; picture-in-picture; web-share"
      allowFullScreen />
  );
}

function toEmbedUrl(url) {
  try {
    const u = new URL(url.trim());
    if (u.hostname.includes("youtube.com")) {
      const v = u.searchParams.get("v");
      if (v) return `https://www.youtube.com/embed/${v}`;
      if (u.pathname.startsWith("/embed/")) return url.trim();
      if (u.pathname.startsWith("/shorts/")) return `https://www.youtube.com/embed/${u.pathname.split("/")[2]}`;
    }
    if (u.hostname === "youtu.be") return `https://www.youtube.com/embed${u.pathname}`;
    if (u.hostname.includes("vimeo.com") && !u.hostname.includes("player")) {
      const id = u.pathname.split("/").filter(Boolean)[0];
      if (id) return `https://player.vimeo.com/video/${id}`;
    }
    return url.trim();
  } catch (e) { return url.trim(); }
}

/* ---------- pdf helper: open or download a stored PDF data URL ---------- */
function pdfActions(dataUrl, filename) {
  const base64 = dataUrl.split(",")[1];
  const bytes = Uint8Array.from(atob(base64), (ch) => ch.charCodeAt(0));
  const url = URL.createObjectURL(new Blob([bytes], { type: "application/pdf" }));
  return {
    url,
    download() {
      const a = document.createElement("a");
      a.href = url; a.download = filename || "document.pdf";
      document.body.appendChild(a); a.click(); document.body.removeChild(a);
    },
    revoke() { setTimeout(() => URL.revokeObjectURL(url), 60000); },
  };
}

/* ---------- export helpers (CSV / XLSX / generic print) ---------- */
function downloadBlobFile(blob, filename) {
  const url = URL.createObjectURL(blob);
  const a = document.createElement("a");
  a.href = url; a.download = filename;
  document.body.appendChild(a); a.click(); document.body.removeChild(a);
  URL.revokeObjectURL(url);
}
function exportRowsCSV(rows, filename) {
  if (!rows.length) return;
  const headers = Object.keys(rows[0]);
  const esc = (v) => `"${String(v ?? "").replace(/"/g, '""')}"`;
  const csv = [headers.map(esc).join(","), ...rows.map((r) => headers.map((h) => esc(r[h])).join(","))].join("\n");
  downloadBlobFile(new Blob([csv], { type: "text/csv;charset=utf-8;" }), filename);
}
function exportSheetsXLSX(sheets, filename) {
  const wb = XLSX.utils.book_new();
  sheets.forEach(({ name, rows }) => {
    if (!rows.length) rows = [{ note: "no data" }];
    XLSX.utils.book_append_sheet(wb, XLSX.utils.json_to_sheet(rows), name.slice(0, 31));
  });
  const out = XLSX.write(wb, { bookType: "xlsx", type: "array" });
  downloadBlobFile(new Blob([out], { type: "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet" }), filename);
}

/* ---------- session + API helpers (server-side auth, Phase 1) ---------- */
let remoteEverWorked = false;   // once true, we never silently fall back to local-only mode
let authToken = null;
try { authToken = window.localStorage ? window.localStorage.getItem("gsSession") : null; } catch (e) {}
function setAuthToken(t) {
  authToken = t;
  try {
    if (window.localStorage) t ? window.localStorage.setItem("gsSession", t) : window.localStorage.removeItem("gsSession");
  } catch (e) {}
}
const authHeaders = () => (authToken ? { Authorization: `Bearer ${authToken}` } : {});

async function apiCall(method, path, body) {
  if (remoteStorage === false) { const e = new Error("local"); e.local = true; throw e; }
  let r;
  try {
    r = await fetch(`/api/${path}`, {
      method,
      headers: { "Content-Type": "application/json", ...authHeaders() },
      body: body !== undefined ? JSON.stringify(body) : undefined,
    });
  } catch (ex) { remoteStorage = false; const e = new Error("local"); e.local = true; throw e; }
  let j;
  try { j = await r.json(); } catch (ex) {
    // Non-JSON response means there's no backend here (e.g. preview) — use local mode
    remoteStorage = false; const e = new Error("local"); e.local = true; throw e;
  }
  remoteStorage = true; remoteEverWorked = true;
  if (!r.ok) { const e = new Error(j.error || "Request failed."); e.status = r.status; throw e; }
  return j;
}
const apiGet = (path) => apiCall("GET", path);
const apiPost = (path, body) => apiCall("POST", path, body);

