/* ---------- storage helpers ----------
   Primary: Netlify Blobs via the /api/storage function (shared across all
   visitors and devices). Fallback: local browser/artifact storage, so the
   prototype still works in previews where the API doesn't exist. */
const mem = {};
let remoteStorage = null; // null = unknown, true/false after first probe

async function loadKey(key, fallback) {
  if (remoteStorage !== false) {
    try {
      const r = await fetch(`/api/storage?key=${encodeURIComponent(key)}`, { headers: authHeaders() });
      let j = null;
      try { j = await r.json(); } catch (e) { j = null; }
      if (j === null) { remoteStorage = false; }
      else {
        remoteStorage = true; remoteEverWorked = true;
        if (r.ok) return j.value != null ? JSON.parse(j.value) : fallback;
        return fallback; // 401/403/404 from the server: no access to this key
      }
    } catch (e) { remoteStorage = false; }
  }
  try {
    if (window.storage) {
      const r = await window.storage.get(key);
      return r ? JSON.parse(r.value) : fallback;
    }
  } catch (e) { /* key missing */ }
  return mem[key] !== undefined ? mem[key] : fallback;
}

async function saveKey(key, value) {
  mem[key] = value;
  if (remoteStorage !== false) {
    try {
      const r = await fetch(`/api/storage?key=${encodeURIComponent(key)}`, {
        method: "PUT",
        headers: { "Content-Type": "application/json", ...authHeaders() },
        body: JSON.stringify(value),
      });
      let j = null;
      try { j = await r.json(); } catch (e) { j = null; }
      if (j === null) { remoteStorage = false; }
      else { remoteStorage = true; return; } // server accepted or rejected — either way, don't double-write locally
    } catch (e) { remoteStorage = false; }
  }
  try {
    if (window.storage) await window.storage.set(key, JSON.stringify(value));
  } catch (e) { console.error("storage save failed", e); }
}

