/* ---------- auth helpers: salted password hashing + TOTP 2FA ---------- */
const textEnc = new TextEncoder();
async function hashPassword(password, salt) {
  const digest = await crypto.subtle.digest("SHA-256", textEnc.encode(salt + "::" + password));
  return Array.from(new Uint8Array(digest)).map((b) => b.toString(16).padStart(2, "0")).join("");
}
const B32 = "ABCDEFGHIJKLMNOPQRSTUVWXYZ234567";
function makeTotpSecret() {
  const bytes = crypto.getRandomValues(new Uint8Array(20));
  let bits = "", out = "";
  bytes.forEach((b) => (bits += b.toString(2).padStart(8, "0")));
  for (let i = 0; i + 5 <= bits.length; i += 5) out += B32[parseInt(bits.slice(i, i + 5), 2)];
  return out;
}
function b32decode(s) {
  let bits = "";
  for (const ch of s.replace(/=+$/, "").toUpperCase()) {
    const v = B32.indexOf(ch);
    if (v >= 0) bits += v.toString(2).padStart(5, "0");
  }
  const bytes = [];
  for (let i = 0; i + 8 <= bits.length; i += 8) bytes.push(parseInt(bits.slice(i, i + 8), 2));
  return new Uint8Array(bytes);
}
async function totpAt(secret, counter) {
  const key = await crypto.subtle.importKey("raw", b32decode(secret), { name: "HMAC", hash: "SHA-1" }, false, ["sign"]);
  const buf = new ArrayBuffer(8);
  new DataView(buf).setUint32(4, counter); // 32-bit counter is fine until ~year 4000
  const h = new Uint8Array(await crypto.subtle.sign("HMAC", key, buf));
  const off = h[h.length - 1] & 0x0f;
  const code = (((h[off] & 0x7f) << 24) | (h[off + 1] << 16) | (h[off + 2] << 8) | h[off + 3]) % 1000000;
  return String(code).padStart(6, "0");
}
async function verifyTotp(secret, code) {
  const t = Math.floor(Date.now() / 30000);
  for (const w of [-1, 0, 1]) if ((await totpAt(secret, t + w)) === code.trim()) return true;
  return false;
}
const sixDigits = () => String(Math.floor(100000 + Math.random() * 900000));

