/* ============================================================ */
export default function App() {
  const [view, setView] = useState("home");
  const [menuOpen, setMenuOpen] = useState(false);
  const [ogOpen, setOgOpen] = useState(false);
  const [classes, setClasses] = useState([]);
  const [certs, setCerts] = useState([]);
  const [apps, setApps] = useState([]);
  const [notices, setNotices] = useState([]);
  const [codes, setCodes] = useState([]);
  const [loaded, setLoaded] = useState(false);
  const [portalUser, setPortalUser] = useState(null);
  const [accounts, setAccounts] = useState([]);
  const [requests, setRequests] = useState([]);
  const [media, setMedia] = useState({ photos: [], videos: [] });
  const [adminUser, setAdminUser] = useState(null);
  const [adminAccounts, setAdminAccounts] = useState([]);

  useEffect(() => {
    (async () => {
      const c = await loadKey("gs:classes", null);
      setClasses(c || SEED_CLASSES);
      if (!c) await saveKey("gs:classes", SEED_CLASSES);
      setCerts(await loadKey("gs:certs", []));
      setApps(await loadKey("gs:apps", []));
      setNotices(await loadKey("gs:notices", []));
      setCodes(await loadKey("gs:codes", []));
      setAccounts(await loadKey("gs:accounts", []));
      {
        // load requests and collapse accidental double-submissions
        const rawReqs = await loadKey("gs:requests", []);
        const seen = [];
        const deduped = rawReqs.filter((r) => {
          const dupe = seen.find((s) =>
            s.email?.toLowerCase() === r.email?.toLowerCase() &&
            s.area?.toLowerCase() === r.area?.toLowerCase() &&
            Math.abs(new Date(s.submittedAt) - new Date(r.submittedAt)) < 120000
          );
          if (dupe) return false;
          seen.push(r);
          return true;
        });
        setRequests(deduped);
        if (deduped.length !== rawReqs.length) await saveKey("gs:requests", deduped);
      }
      setAdminAccounts(await loadKey("gs:adminAccounts", []));
      {
        const defaultPhotos = [
          { id: "p1", src: SHIELD_FRONT, caption: "Whiteboard face — classroom ready" },
          { id: "p2", src: SHIELD_BACK, caption: "Ballistic core, grip & rating label" },
          { id: "p3", src: GALLERY_EAGLE, caption: 'Custom print — "American Eagle"' },
          { id: "p4", src: GALLERY_SECURITY, caption: "Branded print — company logo & badge" },
          { id: "p5", src: GALLERY_CHURCH, caption: "Sanctuary-ready — church print" },
          { id: "p6", src: GALLERY_WALL, caption: "Installed — protection hiding in plain sight" },
        ];
        const m = await loadKey("gs:media", null);
        setMedia(m || { photos: defaultPhotos, videos: [] });
        if (!m) await saveKey("gs:media", { photos: defaultPhotos, videos: [] });
      }
      setLoaded(true);
    })();
  }, []);

  const updateClasses = async (next) => { setClasses(next); await saveKey("gs:classes", next); };
  const updateCerts = async (next) => { setCerts(next); await saveKey("gs:certs", next); };
  const updateApps = async (next) => { setApps(next); await saveKey("gs:apps", next); };
  const updateNotices = async (next) => { setNotices(next); await saveKey("gs:notices", next); };
  const updateCodes = async (next) => { setCodes(next); await saveKey("gs:codes", next); };
  const updateAccounts = async (next) => { setAccounts(next); await saveKey("gs:accounts", next); };
  const updateRequests = async (next) => { setRequests(next); await saveKey("gs:requests", next); };
  const updateMedia = async (next) => { setMedia(next); await saveKey("gs:media", next); };

  // Restore a saved session on load (server-side auth)
  useEffect(() => {
    (async () => {
      if (!authToken) return;
      try {
        const r = await apiGet("auth/me");
        if (r.account.role === "admin") setAdminUser(r.account);
        else setPortalUser(r.account);
      } catch (e) { if (!e.local) setAuthToken(null); }
    })();
  }, []);

  // Re-fetch all protected data (fresh registrations, applications, notices…)
  const reloadProtected = async () => {
    setClasses(await loadKey("gs:classes", []));
    setCerts(await loadKey("gs:certs", []));
    setApps(await loadKey("gs:apps", []));
    setNotices(await loadKey("gs:notices", []));
    setCodes(await loadKey("gs:codes", []));
    setRequests(await loadKey("gs:requests", []));
  };

  // After sign-in, and every time the portal is opened, pull fresh data
  useEffect(() => { if (portalUser) reloadProtected(); }, [portalUser]);
  useEffect(() => { if (view === "portal" && portalUser) reloadProtected(); }, [view]);

  const reloadClasses = async () => setClasses(await loadKey("gs:classes", []));

  // Returning from Stripe checkout (?reg=success|cancel)
  const [stripeReturn, setStripeReturn] = useState(null);
  const [signToken, setSignToken] = useState(null);
  const [adminInvite, setAdminInvite] = useState(null);
  useEffect(() => {
    let q;
    try { q = new URLSearchParams(window.location.search); } catch (e) { return; }
    const reg = q.get("reg");
    const deepView = q.get("view");
    const signTok = q.get("sign");
    const invTok = q.get("invite");
    if (!reg && !deepView && !signTok && !invTok) return;
    try { window.history.replaceState({}, "", window.location.pathname); } catch (e) {}
    const VALID_VIEWS = ["home", "product", "training", "schedule", "about", "verify", "instructor", "portal", "admin", "onguard"];
    if (signTok && signTok.length >= 10) { setSignToken(signTok); setView("sign"); }
    if (invTok && invTok.length >= 10) { setAdminInvite(invTok); setView("admin"); }
    if (deepView && VALID_VIEWS.includes(deepView)) setView(deepView);
    if (!reg) return;
    if (reg === "cancel") { setStripeReturn({ status: "cancel" }); return; }
    const sid = q.get("session_id");
    if (reg !== "success" || !sid) return;
    setStripeReturn({ status: "checking" });
    (async () => {
      for (let i = 0; i < 8; i++) {
        try {
          const r = await apiGet(`checkout-status?session_id=${encodeURIComponent(sid)}`);
          if (r.status === "complete") {
            setStripeReturn({ status: "complete", ref: r.ref });
            setClasses(await loadKey("gs:classes", []));
            return;
          }
        } catch (e) { break; }
        await new Promise((res) => setTimeout(res, 1500));
      }
      setStripeReturn({ status: "processing" });
    })();
  }, []);
  const updateAdminAccounts = async (next) => { setAdminAccounts(next); await saveKey("gs:adminAccounts", next); };

  const redeemCode = async (codeId) => {
    const next = codes.map((k) => (k.id === codeId ? { ...k, uses: (k.uses || 0) + 1 } : k));
    await updateCodes(next);
  };

  const registerStudent = async (classId, student) => {
    const cls = classes.find((c) => c.id === classId);
    const next = classes.map((c) =>
      c.id === classId ? { ...c, enrolled: [...(c.enrolled || []), student] } : c
    );
    await updateClasses(next);
    const note = {
      id: uid(),
      when: new Date().toLocaleString(),
      classId,
      text: `New registration — ${student.name} (${student.email}) enrolled in the ${cls.type === "instructor" ? "Instructor Course" : "2-Day Certification"} scheduled for ${cls.date} at ${classPlace(cls)}. Paid $${(student.paid ?? cls.price).toFixed(2)}${student.discountCode ? ` (code ${student.discountCode})` : ""}.`,
      read: false,
    };
    await updateNotices([note, ...notices]);
  };

  const nav = [
    ["home", "Home"],
    ["onguard", "OnGuard"],
    ["product", "The Shield"],
    ["training", "The Training"],
    ["schedule", "Class Schedule"],
    ["verify", "Verify a Certification"],
    ["instructor", "Become an Instructor"],
    ["portal", "Instructor Portal"],
    ["about", "About"],
  ];

  return (
    <div style={{ ...body, background: C.bg, minHeight: "100vh", color: C.text }}>
      <style>{FONTS}</style>

      {/* ---------- top bar ---------- */}
      <header style={{ background: C.header, borderBottom: `1px solid ${C.bronzeDark}`, position: "sticky", top: 0, zIndex: 40 }}>
        <div style={{ maxWidth: 1140, margin: "0 auto", padding: "0 20px", display: "flex", alignItems: "center", gap: 24, flexWrap: "wrap" }}>
          <button onClick={() => setView("home")} style={{ background: "none", border: "none", cursor: "pointer", display: "flex", alignItems: "center", gap: 12, padding: "10px 0", color: C.text }}>
            <img src={LOGO} alt="Guardian Rapid Response Shield emblem" style={{ width: 46, height: 46, borderRadius: "50%", boxShadow: `0 0 0 1px ${C.bronzeDark}` }} />
            <span style={{ textAlign: "left" }}>
              <span style={{ ...display, fontWeight: 800, fontSize: 22, letterSpacing: "0.08em", display: "block", lineHeight: 1, color: C.bronzeLight }}>GUARDIAN SHIELD</span>
              <span style={{ ...mono, fontSize: 10, letterSpacing: "0.22em", color: C.muted }}>TRAINING</span>
            </span>
          </button>
          <nav className="gs-nav-desktop">
            {nav.map(([id, label]) => (
              id === "onguard" ? (
                <span key={id} style={{ position: "relative", display: "inline-block" }}
                  onMouseEnter={() => setOgOpen(true)} onMouseLeave={() => setOgOpen(false)}>
                  <button onClick={() => { setView(id); setOgOpen(false); }}
                    style={{ ...display, fontWeight: 600, fontSize: 15, letterSpacing: "0.05em", textTransform: "uppercase",
                      background: view === id ? C.bronze : "transparent", color: view === id ? "#1A1509" : C.text, border: "none",
                      padding: "8px 12px", cursor: "pointer", borderRadius: 2 }}>
                    {label} ▾
                  </button>
                  {ogOpen && (
                    <div style={{ position: "absolute", left: 0, top: "100%", minWidth: 320, background: C.header, border: `1px solid ${C.bronzeDark}`, boxShadow: "0 10px 30px rgba(0,0,0,0.5)", zIndex: 60 }}>
                      {ONGUARD_TOOLS.map((t) => (
                        <a key={t.href} href={t.href} target="_blank" rel="noopener noreferrer" onClick={() => setOgOpen(false)}
                          style={{ ...display, fontWeight: 600, fontSize: 14, letterSpacing: "0.04em", textTransform: "uppercase", display: "block",
                            color: C.text, textDecoration: "none", padding: "12px 16px", borderBottom: `1px solid ${C.line}` }}>
                          <span style={{ ...mono, color: C.bronze, fontSize: 12, marginRight: 8 }}>{t.n}.</span>{t.title}
                        </a>
                      ))}
                    </div>
                  )}
                </span>
              ) : (
              <button key={id} onClick={() => setView(id)}
                style={{ ...display, fontWeight: 600, fontSize: 15, letterSpacing: "0.05em", textTransform: "uppercase",
                  background: view === id ? C.bronze : "transparent", color: view === id ? "#1A1509" : C.text, border: "none",
                  padding: "8px 12px", cursor: "pointer", borderRadius: 2 }}>
                {label}
              </button>
              )
            ))}
          </nav>
          <button className="gs-nav-toggle" onClick={() => setMenuOpen(!menuOpen)} aria-label="Open menu" aria-expanded={menuOpen}
            style={{ background: "none", border: `1px solid ${C.bronzeDark}`, color: C.bronzeLight, fontSize: 20, lineHeight: 1, padding: "8px 14px", cursor: "pointer", borderRadius: 2 }}>
            {menuOpen ? "✕" : "☰"}
          </button>
        </div>
        {menuOpen && (
          <div style={{ borderTop: `1px solid ${C.line}`, background: C.header }}>
            {nav.map(([id, label]) => (
              <React.Fragment key={id}>
                <button onClick={() => { setView(id); setMenuOpen(false); }}
                  style={{ ...display, fontWeight: 600, fontSize: 17, letterSpacing: "0.05em", textTransform: "uppercase",
                    display: "block", width: "100%", textAlign: "left",
                    background: view === id ? C.bronze : "transparent", color: view === id ? "#1A1509" : C.text,
                    border: "none", borderBottom: `1px solid ${C.line}`, padding: "14px 20px", cursor: "pointer" }}>
                  {label}
                </button>
                {id === "onguard" && ONGUARD_TOOLS.map((t) => (
                  <a key={t.href} href={t.href} target="_blank" rel="noopener noreferrer" onClick={() => setMenuOpen(false)}
                    style={{ ...display, fontWeight: 600, fontSize: 15, letterSpacing: "0.04em", textTransform: "uppercase",
                      display: "block", width: "100%", textAlign: "left", boxSizing: "border-box", color: C.muted, textDecoration: "none",
                      borderBottom: `1px solid ${C.line}`, padding: "12px 20px 12px 40px" }}>
                    <span style={{ ...mono, color: C.bronze, fontSize: 12, marginRight: 8 }}>{t.n}.</span>{t.title}
                  </a>
                ))}
              </React.Fragment>
            ))}
          </div>
        )}
      </header>

      {!loaded ? (
        <div style={{ padding: 80, textAlign: "center", color: C.muted }}>Loading…</div>
      ) : (
        <>
          {stripeReturn && (
            <Modal title={stripeReturn.status === "cancel" ? "Checkout cancelled" : stripeReturn.status === "complete" ? "You're registered!" : "Confirming your payment"} onClose={() => setStripeReturn(null)}>
              {stripeReturn.status === "checking" && (
                <p style={{ fontSize: 15, color: C.muted, lineHeight: 1.6 }}>One moment — confirming your payment with Stripe…</p>
              )}
              {stripeReturn.status === "complete" && (
                <div style={{ display: "grid", gap: 10 }}>
                  <p style={{ fontSize: 15, color: C.text, lineHeight: 1.6, margin: 0 }}>Payment received and your seat is reserved. Your registration reference:</p>
                  <div style={{ ...mono, fontSize: 20, color: C.bronzeLight, background: C.panel2, border: `1px solid ${C.bronzeDark}`, padding: "10px 14px", textAlign: "center" }}>{stripeReturn.ref}</div>
                  <p style={{ fontSize: 13, color: C.muted, lineHeight: 1.6, margin: 0 }}>A confirmation email with your class details is on its way. Bring a valid ID to check-in — the range safety briefing and liability waiver are completed on Day 1 before training begins.</p>
                  <Btn onClick={() => setStripeReturn(null)}>Done</Btn>
                </div>
              )}
              {stripeReturn.status === "processing" && (
                <p style={{ fontSize: 15, color: C.muted, lineHeight: 1.6 }}>Payment received — your registration is being recorded and will appear shortly. If it doesn't show on the schedule within a few minutes, contact us with your Stripe receipt.</p>
              )}
              {stripeReturn.status === "cancel" && (
                <p style={{ fontSize: 15, color: C.muted, lineHeight: 1.6 }}>No worries — your card was not charged and no seat was reserved. You can register any time from the Class Schedule.</p>
              )}
            </Modal>
          )}
          {view === "sign" && signToken && <SignPage token={signToken} />}
          {view === "home" && <Home go={setView} media={media} />}
          {view === "product" && <Product go={setView} media={media} />}
          {view === "about" && <About go={setView} />}
          {view === "onguard" && <OnGuard />}
          {view === "admin" && (
            <AdminPortal
              user={adminUser} setUser={setAdminUser} instrAccounts={accounts}
              accounts={adminAccounts} updateAccounts={updateAdminAccounts}
              media={media} updateMedia={updateMedia} go={setView} inviteToken={adminInvite}
            />
          )}
          {view === "training" && <Training go={setView} media={media} />}
          {view === "schedule" && <Schedule classes={classes} onRegister={registerStudent} codes={codes} redeemCode={redeemCode} requests={requests} updateRequests={updateRequests} apps={apps} updateApps={updateApps} reloadClasses={reloadClasses} />}
          {view === "verify" && <Verify certs={certs} />}
          {view === "instructor" && <InstructorApply apps={apps} updateApps={updateApps} go={setView} classes={classes} />}
          {view === "portal" && (
            <Portal
              inviteToken={adminInvite}
              user={portalUser} setUser={setPortalUser} reloadData={reloadProtected}
              accounts={accounts} updateAccounts={updateAccounts}
              classes={classes} updateClasses={updateClasses}
              certs={certs} updateCerts={updateCerts}
              notices={notices} updateNotices={updateNotices}
              apps={apps} updateApps={updateApps} codes={codes} updateCodes={updateCodes}
              requests={requests} updateRequests={updateRequests}
            />
          )}
        </>
      )}

      <footer style={{ background: C.header, borderTop: `1px solid ${C.line}`, color: C.muted, marginTop: 64 }}>
        <div style={{ maxWidth: 1140, margin: "0 auto", padding: "26px 20px", display: "flex", alignItems: "center", gap: 14, flexWrap: "wrap" }}>
          <img src={LOGO} alt="" style={{ width: 34, height: 34, borderRadius: "50%", opacity: 0.9 }} />
          <span style={{ fontSize: 13 }}>© 2026 Guardian Shield Training. <span style={{ color: C.bronze }}>Protect what matters most.</span></span>
          <span style={{ ...mono, fontSize: 12, marginLeft: "auto" }}>certifications valid 24 months from issue</span>
        </div>
      </footer>
    </div>
  );
}

